+resolve_default_smoke_platform() {
+  local host_os
+  local host_arch
+  if [[ -n "${OPENCLAW_INSTALL_SMOKE_PLATFORM:-}" ]]; then
+    printf "%s" "$OPENCLAW_INSTALL_SMOKE_PLATFORM"
+    return
+  fi
+  if [[ "${CI:-}" == "true" || "${GITHUB_ACTIONS:-}" == "true" ]]; then
+    printf "linux/amd64"
+    return
+  fi
+  host_os="$(uname -s)"
+  host_arch="$(uname -m)"
+  if [[ "$host_os" == "Darwin" && "$host_arch" == "arm64" ]]; then
+    printf "linux/arm64"
+    return
+  fi
+  printf "linux/amd64"
+}
